SourceCode.Declaration:
/// <summary>
/// Service class to modify unsold inventory transactions in the ETGSPAIN model.
/// </summary>
class ETGSPAINUnsoldInventTransModifyService extends SysOperationServiceBase
{
}

Method.Source:
    /// <summary>
    /// Processes the modification of the unsold inventory transaction based on the contract.
    /// </summary>
    /// <param name="_contract">The contract that contains the necessary parameters for modifying the transaction.</param>
    public void process(ETGSPAINUnsoldInventTransModifyContract _contract)
	{        
        ttsbegin;
        ETGSPAINUnsoldInventTrans   etgspainUnsoldInventTrans = ETGSPAINUnsoldInventTrans::findRefRecId(_contract.parmRefRecId(), true, true);

        etgspainUnsoldInventTrans.UnsoldQty = _contract.parmETGSPAINUnsoldQty();

        if (_contract.parmUpdateMaxUnsoldQty())
        {
            etgspainUnsoldInventTrans.MaxUnsoldQty = _contract.parmUpdateMaxUnsoldQty();
        }

        etgspainUnsoldInventTrans.update();
        ttscommit;
	}
